#include <iostream>
#include <cmath>

double ln2_exp_series(int terms) {
  double lnValue = 0.0;

  for (int n = 1; n <= terms; n++) {
    lnValue += (pow(2, n) / n); // Series expansion
  }
  return lnValue;
}

int main() {
  double ln2 = ln2_exp_series(100000);
  std::cout << "Approximation of ln(2) using Taylor series for e^x = " << ln2 << std::endl;
  return 0;
