#include <iostream>

double ln2_continued_fraction(int terms) {
  double fraction = 0.0;

  for (int i = terms - 1; i > 0; i--) {
    fraction = 1.0 / (i + fraction);
  }
  return 1 + fraction; // Adding the initial 1
}

int main() {
  double ln2 = ln2_continued_fraction(100);
  std::cout << "Approximation of ln(2) using continued fractions = " << ln2 << std::endl;
  return 0;
