public static void mettreAJourBien(String id) {
  if (!biensImmobiliers.containsKey(id)) {
    System.out.println("Erreur: Bien non trouvé.");
    return;
  }

  System.out.println("Informations actuelles pour " + id + ": " + biensImmobiliers.get(id));
  Scanner scanner = new Scanner(System.in);

  System.out.print("Nouvelle prix (laisser vide pour ne pas changer): ");
  String prixInput = scanner.nextLine();

  System.out.print("Nouvelle disponibilité (1 pour oui, 0 pour non, laisser vide pour ne pas changer): ");
  String dispoInput = scanner.nextLine();

  boolean updated = false;
  HashMap<String, Object> bien = biensImmobiliers.get(id);

  if (!prixInput.isEmpty()) {
    try {
      bien.put("prix", Integer.parseInt(prixInput));
      updated = true;
      System.out.println("Prix mis à jour.");
    } catch (NumberFormatException e) {
      System.out.println("Erreur: Prix doit être un nombre.");
    }
  }

  if (!dispoInput.isEmpty()) {
    if (dispoInput.equals("1") || dispoInput.equals("0")) {
      bien.put("disponibilite", dispoInput.equals("1"));
      updated = true;
      System.out.println("Disponibilité mise à jour.");
    } else {
      System.out.println("Erreur: Disponibilité doit être 0 ou 1.");
    }
  }

  if (!updated) {
    System.out.println("Aucune mise à jour effectuée.");
  } else {
    System.out.println("Bien mis à jour: " + id + " - " + bien);
  }
}

