import Java.util.Scanner;

public class PyramideReguliere {
  public static double aireBasePolygonale(int n, double longueur) {
    return (n * Math.pow(longueur, 2)) / (4 * Math.tan(Math.PI / n));
  }

  public static double[] calculerPyramideReguliere(int n, double longueurBase, double hauteur) {
    // Calcul du volume
    double aireBase = aireBasePolygonale(n, longueurBase);
    double volume = (1.0 / 3) * aireBase * hauteur;

    // Calcul de l'aire de la surface
    double apotheme = Math.sqrt(Math.pow(hauteur, 2) + Math.pow(longueurBase / 2, 2));
    double aireSurfaceLat = n * longueurBase * apotheme / 2;
    double aireSurface = aireSurfaceLat + aireBase;

    return new double[] { volume, aireSurface };
  }

  public static void main(String[] args) {
    Scanner scanner = new Scanner(System.in);

    // Saisie des dimensions
    System.out.print("Entrez le nombre de côtés de la base polygonale : ");
    int n = scanner.nextInt();
    System.out.print("Entrez la longueur de chaque côté de la base polygonale : ");
    double longueurBase = scanner.nextDouble();
    System.out.print("Entrez la hauteur de la pyramide : ");
    double hauteur = scanner.nextDouble();

    double[] resultats = calculerPyramideReguliere(n, longueurBase, hauteur);
    double volume = resultats[0];
    double aireSurface = resultats[1];

    System.out.printf("Volume de la pyramide régulière : %.2f\n", volume);
    System.out.printf("Aire de la surface de la pyramide régulière : %.2f\n", aireSurface);

    scanner.close();
  }
