class Robot:
  def __init__(self):
    self.x = 0
    self.y = 0
    self.speed = 1
    self.history = []

  def move(self, direction):
    if direction == "up":
      self.y += self.speed
    elif direction == "down":
      self.y -= self.speed
    elif direction == "left":
      self.x -= self.speed
    elif direction == "right":
      self.x += self.speed
    else:
      print("Invalid direction")
      return

    self.history.append(direction)

  def set_speed(self, speed):
    if 1 <= speed <= 3:
      self.speed = speed
      print(f"Speed set to {self.speed}")
    else:
      print("Invalid speed. Please set between 1 and 3.")

  def get_position(self):
    return self.x, self.y

