#include <iostream>

void simulate_epidemic_with_birth_death(int days, double beta, double gamma, double birth_rate, double death_rate, int initial_infected, int population) {
  double susceptible = population - initial_infected;
  double infected = initial_infected;
  double recovered = 0;

  for (int day = 0; day < days; day++) {
    double new_infected = beta * susceptible * infected / population;
    double new_recovered = gamma * infected;
    double births = birth_rate * population;
    double deaths = death_rate * (susceptible + infected + recovered);

    susceptible += births - deaths;
    infected += new_infected - new_recovered;
    recovered += new_recovered;

    std::cout << "Day " << day << ": Susceptible: " << susceptible << ", Infected: " << infected << ", Recovered: " << recovered << std::endl;
  }
}

int main() {
  simulate_epidemic_with_birth_death(30, 0.3, 0.1, 0.01, 0.005, 1, 1000);
  return 0;
